template<typename T>
MT::Log2Table<2000000> MT::ST<T>::Log2;
int dp[N][20];
void solve(int CASE)
{
	ll n, k, d; cin >> n >> k >> d;
	var h = vector<ll>(n + 1);
	fa(i, 1, n)cin >> h[i];

	///////////// 1 /////////////
	var check1 = [&](ll mid)->bool {
		ll cnt = 1;
		ll mx = h[1], mn = h[1];
		fa(i, 2, n) {
			if (mx - h[i] > mid or h[i] - mn > mid) {
				mx = h[i], mn = h[i];
				cnt++;
			}
			else mx = max(mx, h[i]), mn = min(mn, h[i]);
		}
		return cnt <= k;
		};
	ll l = 1, r = 1e9, ans1 = 0;
	while (l <= r) {
		ll mid = l + r >> 1;
		if (check1(mid)) {
			r = mid - 1;
			ans1 = mid;
		}
		else l = mid + 1;
	}

	///////////// 2 /////////////
	ll ans2 = 1;
	ll mx = h[1], mn = h[1];
	fa(i, 2, n) {
		if (mx - h[i] > d or h[i] - mn > d) {
			mx = h[i], mn = h[i];
			ans2++;
		}
		else mx = max(mx, h[i]), mn = min(mn, h[i]);
	}

	///////////// 3 /////////////
	var stmn = MT::ST<ll>(h, MT::ST<ll>::_min);
	var stmx = MT::ST<ll>(h, MT::ST<ll>::_max);
	var R = vector<int>(n + 1); // 从 i 出发，最远能到达的不需要换行的位置
	fa(i, 1, n) {
		int l = i, r = n;
		R[i] = i;
		while (l <= r) {
			int mid = l + r >> 1;
			if (abs(stmx.queryMax(i, mid) - stmn.queryMin(i, mid)) <= d) {
				l = mid + 1;
				R[i] = mid;
			}
			else r = mid - 1;
		}
	}

	// 在 i 位置跳一次，到达 R[i] + 1，即换行后的第一个位置
	fa(i, 1, n)dp[i][0] = R[i] + 1;
	dp[n + 1][0] = n + 1;
	fa(j, 1, 19) 
		fa(i, 1, n + 1) 
			dp[i][j] = max(dp[i][j - 1], dp[dp[i][j - 1]][j - 1]);

	// 换 k 行，即最多跳 k 次
	int ans3 = 1;
	fa(i, 1, n) {
		int now = i;
		fa(j, 0, 19) 
			if (k & (1ll << j)) 
				now = dp[now][j];
		ans3 = max(ans3, now - i);
	}

	//int ans4 = 0;
	//fa(i, 1, n)
	//	fa(j, i, n) {
	//	ll cnt = 1;
	//	ll mx = h[i], mn = h[i];
	//	fa(q, i, j) {
	//		if (mx - h[q] > d or h[q] - mn > d) {
	//			mx = h[q], mn = h[q];
	//			cnt++;
	//		}
	//		else mx = max(mx, h[q]), mn = min(mn, h[q]);
	//	}
	//	if (cnt <= k)ans4 = max(j - i + 1, ans4);
	//}
	//if (ans3 != ans4) {
	//	debug("NOOOOOOOOOOOOOOOOOOO");
	//	debug(ans3, ans4);
	//	debug(n, k, d);
	//	fa(i, 1, n)cout << h[i] << ' ';
	//	cout << endl;
	//}

	cout << ans1 << endl << ans2 << endl << ans3 << endl;
	return;
}
